import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

const Profile = () => {
  const [user, setUser] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    const userData = localStorage.getItem('study_portal_user');
    const token = localStorage.getItem('study_portal_token');
    
    if (!token || !userData) {
      navigate('/login');
      return;
    }
    
    setUser(JSON.parse(userData));
  }, [navigate]);

  const styles = {
    container: {
      padding: '2rem',
      maxWidth: '800px',
      margin: '2rem auto',
      minHeight: '70vh'
    },
    card: {
      background: 'white',
      borderRadius: '12px',
      padding: '2rem',
      boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
    },
    header: {
      display: 'flex',
      alignItems: 'center',
      gap: '2rem',
      marginBottom: '2rem'
    },
    avatar: {
      width: '80px',
      height: '80px',
      borderRadius: '50%',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      color: 'white',
      fontSize: '2rem',
      fontWeight: 'bold'
    },
    name: {
      fontSize: '2rem',
      color: '#1e293b'
    },
    email: {
      color: '#64748b',
      fontSize: '1rem'
    },
    stats: {
      display: 'grid',
      gridTemplateColumns: 'repeat(3, 1fr)',
      gap: '1rem',
      marginTop: '2rem'
    },
    statBox: {
      textAlign: 'center',
      padding: '1rem',
      background: '#f7fafc',
      borderRadius: '8px'
    }
  };

  if (!user) return null;

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <div style={styles.header}>
          <div style={styles.avatar}>
            {user.name?.charAt(0) || 'U'}
          </div>
          <div>
            <h1 style={styles.name}>{user.name || 'User'}</h1>
            <p style={styles.email}>{user.email || 'user@example.com'}</p>
          </div>
        </div>

        <div style={styles.stats}>
          <div style={styles.statBox}>
            <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#667eea' }}>12</div>
            <div>Uploads</div>
          </div>
          <div style={styles.statBox}>
            <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#667eea' }}>45</div>
            <div>Downloads</div>
          </div>
          <div style={styles.statBox}>
            <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#667eea' }}>3</div>
            <div>Courses</div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Profile;
